using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ExternalApiTool
{
    [McpServerTool, Description("Fetches a post by ID from an external API.")]
    public static async Task<string> GetPost(
        IHttpClientFactory httpClientFactory,
        [Description("The numeric ID of the post to retrieve.")] int id)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");
        var post = await client.GetFromJsonAsync<JsonElement>($"/posts/{id}");
        return post.ToString();
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a prompt that asks for a concise summary of the provided text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text content to summarize.")] string content,
        [Description("Optional maximum number of sentences for the summary.")] string? maxSentences = null)
    {
        var constraint = maxSentences is not null
            ? $" Use no more than {maxSentences} sentences."
            : string.Empty;

        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content
                {
                    Type = "text",
                    Text = $"Please provide a concise summary of the following text.{constraint}\n\n{content}"
                }
            }
        ];
    }
}

